1	export type Customer = {
2	  yearsWithMHPCO: number;
3	  previousContracts: number;
4	};
5	
6	export type Item = {
7	  type: string;
8	  cursed?: boolean;
9	  enchantment?: number;
10	};
11	
12	const PROCESSING_FEE = 5;
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
24	const BLOCK_SIZE = 3;
25	const BLOCK_PREMIUM = 60;
26	const CURSE_SURCHARGE_RATE = 0.5;
27	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
28	const HIGH_ENCHANTMENT_THRESHOLD = 5;
29	const FIRST_INSURANCE_RATE = 0.1;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	const LOYALTY_YEARS_THRESHOLD = 2;
32	const FOLLOWUP_DISCOUNT_RATE = 0.15;
33	const DEDUCTIBLE = 100;
34	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
35	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
36	
37	function itemSurcharge(item: Item): number {
38	  const itemBase = BASE_PREMIUMS[item.type];
39	  let surcharge = 0;
40	  if (item.cursed) surcharge += itemBase * CURSE_SURCHARGE_RATE;
41	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
42	    surcharge += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
43	  }
44	  return surcharge;
45	}
46	
47	function typeSubtotal(type: string, count: number): number {
48	  const isBlock = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
49	  return isBlock ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
50	}
51	
52	function loyaltyDiscount(customer: Customer, policyBase: number): number {
53	  return customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
54	    ? policyBase * LOYALTY_DISCOUNT_RATE
55	    : 0;
56	}
57	
58	function followupDiscount(customer: Customer, policyBase: number): number {
59	  return customer.previousContracts >= 1
60	    ? policyBase * FOLLOWUP_DISCOUNT_RATE
61	    : 0;
62	}
63	
64	export type Damage = {
65	  itemType: string;
66	  amount: number;
67	};
68	
69	function reimbursementAmount(item: Item | undefined, damageAmount: number): number {
70	  const isHighEnchantment =
71	    !!item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
72	  return isHighEnchantment
73	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE * damageAmount
74	    : damageAmount;
75	}
76	
77	export function claim(items: Item[], damages: Damage[]): { payout: number } {
78	  const totalPayout = damages.reduce((sum, damage) => {
79	    const item = items.find((i) => i.type === damage.itemType);
80	    const reimbursed = reimbursementAmount(item, damage.amount);
81	    return sum + Math.max(0, reimbursed - DEDUCTIBLE);
82	  }, 0);
83	  return { payout: Math.floor(totalPayout) };
84	}
85	
86	export function quote(customer: Customer, items: Item[]): number {
87	  const countsByType: Record<string, number> = {};
88	  for (const item of items) {
89	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
90	  }
91	
92	  const policyBase = Object.entries(countsByType)
93	    .reduce((sum, [type, count]) => sum + typeSubtotal(type, count), 0);
94	
95	  const itemSurcharges = items.reduce((sum, item) => sum + itemSurcharge(item), 0);
96	  const loyalty = loyaltyDiscount(customer, policyBase);
97	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
98	  const followup = followupDiscount(customer, policyBase);
99	
100	  return Math.ceil(policyBase + itemSurcharges - loyalty + firstInsurance - followup) + PROCESSING_FEE;
101	}
